INSERT INTO contraindications (dci_pattern,condition_type,condition_valeur,severite,description,mecanisme_fr,conduite_fr)
VALUES
('étanercept','pathologie','Infections actives sévères','absolue','Étanercept contre-indiqué en cas d''infection active sévère : risque de dissémination fatale','Immunosuppression par étanercept (anti-TNF) altère la défense immunitaire anti-infectieuse','Traiter l''infection avant d''initier étanercept. Suspendre si infection intercurrente grave'),
('étanercept','pathologie','Grossesse','absolue','Étanercept tératogène et embryotoxique, contre-indiqué pendant toute la grossesse','Étanercept interfère avec la division cellulaire embryonnaire (anti-TNF)','Contraception efficace obligatoire. Arrêt min. 3 mois avant conception'),
('étanercept','pathologie','Allaitement','absolue','Étanercept passe dans le lait maternel : risque d''immunosuppression du nourrisson','Passage lacté avec risque de toxicité et immunosuppression chez le nourrisson','Contre-indiqué pendant l''allaitement. Sevrage si traitement indispensable'),
('étanercept','pathologie','Insuffisance rénale sévère (DFG < 30 mL/min)','relative','Étanercept s''accumule en insuffisance rénale sévère avec risque de toxicité majorée','Réduction de la clairance rénale de étanercept et/ou ses métabolites actifs','Adapter la dose au DFG. Surveillance créatinine rapprochée. Alternative si possible'),
('étanercept','pathologie','Insuffisance hépatique sévère (Child-Pugh C)','absolue','Étanercept contre-indiqué en IHC sévère par défaut de métabolisation et toxicité cumulée','Métabolisme hépatique altéré de étanercept avec accumulation et hépatotoxicité','Bilan hépatique obligatoire avant traitement. CI si Child-Pugh C'),
('étanercept','pathologie','Tuberculose latente non traitée','absolue','Risque de réactivation de tuberculose latente sous étanercept, potentiellement fatale','Étanercept (anti-TNF) supprime la réponse T cellulaire contrôlant M. tuberculosis latent','Dépistage obligatoire (IDR/IGRA + radio thorax) avant initiation. Prophylaxie si positif'),
('étanercept','pathologie','Néoplasie évolutive non contrôlée','absolue','Étanercept peut favoriser la progression tumorale par immunosuppression','Suppression de la surveillance immunitaire anti-tumorale par étanercept (anti-TNF)','CI relative à absolue selon cancer. Décision multidisciplinaire obligatoire'),
('étanercept','pathologie','Immunodépression sévère préexistante','relative','Cumul immunosuppresseur sous étanercept avec immunodépression préexistante : risque infectieux majeur','Double immunosuppression → déficience immunitaire profonde et infections opportunistes','Évaluation soigneuse. Bilan immunitaire. Prophylaxie anti-infectieuse. Surveillance intensive'),
('étanercept','pathologie','Vaccination par vaccin vivant atténué','absolue','Étanercept contre-indique les vaccins vivants (risque d''infection vaccinale disséminée)','Immunosuppression empêche le contrôle du virus vaccinal atténué','Vaccinations à jour AVANT traitement. Éviter vaccins vivants sous étanercept et 6 mois après'),
('étanercept','pathologie','Neutropénie sévère (PNN < 500/mm³)','absolue','Étanercept aggrave la neutropénie sévère, exposant à un risque infectieux vital','Myélosuppression additionnelle de étanercept sur une moelle déjà défaillante','CI jusqu''à récupération (PNN > 1000/mm³). G-CSF si nécessaire'),
('léflunomide','pathologie','Infections actives sévères','absolue','Léflunomide contre-indiqué en cas d''infection active sévère : risque de dissémination fatale','Immunosuppression par léflunomide (inhibiteur DHODH) altère la défense immunitaire anti-infectieuse','Traiter l''infection avant d''initier léflunomide. Suspendre si infection intercurrente grave'),
('léflunomide','pathologie','Grossesse','absolue','Léflunomide tératogène et embryotoxique, contre-indiqué pendant toute la grossesse','Léflunomide interfère avec la division cellulaire embryonnaire (inhibiteur DHODH)','Contraception efficace obligatoire. Arrêt min. 3 mois avant conception'),
('léflunomide','pathologie','Allaitement','absolue','Léflunomide passe dans le lait maternel : risque d''immunosuppression du nourrisson','Passage lacté avec risque de toxicité et immunosuppression chez le nourrisson','Contre-indiqué pendant l''allaitement. Sevrage si traitement indispensable'),
('léflunomide','pathologie','Insuffisance rénale sévère (DFG < 30 mL/min)','relative','Léflunomide s''accumule en insuffisance rénale sévère avec risque de toxicité majorée','Réduction de la clairance rénale de léflunomide et/ou ses métabolites actifs','Adapter la dose au DFG. Surveillance créatinine rapprochée. Alternative si possible'),
('léflunomide','pathologie','Insuffisance hépatique sévère (Child-Pugh C)','absolue','Léflunomide contre-indiqué en IHC sévère par défaut de métabolisation et toxicité cumulée','Métabolisme hépatique altéré de léflunomide avec accumulation et hépatotoxicité','Bilan hépatique obligatoire avant traitement. CI si Child-Pugh C'),
('léflunomide','pathologie','Tuberculose latente non traitée','relative','Risque de réactivation de tuberculose latente sous léflunomide, potentiellement fatale','Léflunomide (inhibiteur DHODH) supprime la réponse T cellulaire contrôlant M. tuberculosis latent','Dépistage obligatoire (IDR/IGRA + radio thorax) avant initiation. Prophylaxie si positif'),
('léflunomide','pathologie','Néoplasie évolutive non contrôlée','absolue','Léflunomide peut favoriser la progression tumorale par immunosuppression','Suppression de la surveillance immunitaire anti-tumorale par léflunomide (inhibiteur DHODH)','CI relative à absolue selon cancer. Décision multidisciplinaire obligatoire'),
('léflunomide','pathologie','Immunodépression sévère préexistante','relative','Cumul immunosuppresseur sous léflunomide avec immunodépression préexistante : risque infectieux majeur','Double immunosuppression → déficience immunitaire profonde et infections opportunistes','Évaluation soigneuse. Bilan immunitaire. Prophylaxie anti-infectieuse. Surveillance intensive'),
('léflunomide','pathologie','Vaccination par vaccin vivant atténué','absolue','Léflunomide contre-indique les vaccins vivants (risque d''infection vaccinale disséminée)','Immunosuppression empêche le contrôle du virus vaccinal atténué','Vaccinations à jour AVANT traitement. Éviter vaccins vivants sous léflunomide et 6 mois après'),
('léflunomide','pathologie','Neutropénie sévère (PNN < 500/mm³)','absolue','Léflunomide aggrave la neutropénie sévère, exposant à un risque infectieux vital','Myélosuppression additionnelle de léflunomide sur une moelle déjà défaillante','CI jusqu''à récupération (PNN > 1000/mm³). G-CSF si nécessaire'),
('héparine non fractionnée','pathologie','Hémorragie active cliniquement significative','absolue','Héparine non fractionnée (héparine) formellement contre-indiqué en hémorragie active','Tout anticoagulant aggrave le saignement en cours par inhibition de la coagulation','Arrêt immédiat. Antagonisation si disponible. Prise en charge hémorragique urgente'),
('héparine non fractionnée','pathologie','Thrombopénie induite par héparine (TIH)','absolue','Héparine non fractionnée formellement contre-indiqué en cas de TIH confirmée ou suspectée','Anticorps anti-FP4/héparine activent les plaquettes → thrombose paradoxale','Arrêt immédiat. Anticoagulant non-héparinique (argatroban, danaparoïde)'),
('héparine non fractionnée','pathologie','Insuffisance rénale sévère (DFG < 30 mL/min)','relative','Héparine non fractionnée accumulé en insuffisance rénale sévère avec risque hémorragique majeur','Accumulation de héparine non fractionnée en cas d''insuffisance rénale','CI absolue pour AODs (DFG < 30). Préférer HNF si anticoagulation requise'),
('héparine non fractionnée','pathologie','Grossesse','relative','Héparine non fractionnée (héparine) déconseillé — données insuffisantes','Passage placentaire de héparine non fractionnée insuffisamment étudié','HBPM recommandée pendant toute la grossesse comme alternative anticoagulante de référence'),
('héparine non fractionnée','pathologie','Chirurgie récente à haut risque hémorragique','absolue','Héparine non fractionnée contre-indiqué dans les suites immédiates d''une chirurgie à risque hémorragique élevé','Inhibition de la coagulation par héparine non fractionnée compromet l''hémostase chirurgicale','Respecter les délais post-opératoires selon le type de chirurgie et héparine'),
('héparine non fractionnée','pathologie','HTA sévère non contrôlée (PA > 180/110 mmHg)','relative','Héparine non fractionnée déconseillé en HTA sévère non contrôlée par risque d''AVC hémorragique','HTA sévère fragilise les vaisseaux. Anticoagulation par héparine non fractionnée augmente le risque cérébral','Contrôler la PA avant anticoagulation. Évaluation neurologique si nécessaire'),
('héparine non fractionnée','pathologie','Ulcère gastroduodénal actif','absolue','Héparine non fractionnée contre-indiqué en ulcère actif : risque d''hémorragie digestive grave','Anticoagulation par héparine non fractionnée (héparine) aggrave tout saignement sur lésion ulcéreuse','Traiter l''ulcère avant. IPP systématiques si anticoagulation indispensable'),
('héparine non fractionnée','pathologie','AVC hémorragique récent (< 3 mois)','absolue','Héparine non fractionnée formellement contre-indiqué après un AVC hémorragique récent','Risque majeur de récidive ou extension hémorragique cérébrale sous héparine non fractionnée','CI absolue minimum 3 mois. Réévaluation neurologique après ce délai'),
('héparine non fractionnée','pathologie','Endocardite bactérienne','relative','Héparine non fractionnée expose à des emboles septiques hémorragiques en contexte d''endocardite','Végétations fragilisent l''endothélium. Anticoagulation augmente le risque d''AVC hémorragique','CI sauf valve mécanique. Héparine à objectif strict si indispensable'),
('héparine non fractionnée','pathologie','Insuffisance hépatique sévère avec coagulopathie','absolue','Héparine non fractionnée contre-indiqué en IHC sévère avec coagulopathie préexistante','Déficit de synthèse des facteurs coagulation hépatiques + héparine non fractionnée → risque hémorragique extrême','CI absolue. Corriger coagulopathie. Avis hématologique obligatoire'),
('énoxaparine','pathologie','Hémorragie active cliniquement significative','absolue','Énoxaparine (HBPM) formellement contre-indiqué en hémorragie active','Tout anticoagulant aggrave le saignement en cours par inhibition de la coagulation','Arrêt immédiat. Antagonisation si disponible. Prise en charge hémorragique urgente'),
('énoxaparine','pathologie','Thrombopénie induite par héparine (TIH)','absolue','Énoxaparine formellement contre-indiqué en cas de TIH confirmée ou suspectée','Anticorps anti-FP4/héparine activent les plaquettes → thrombose paradoxale','Arrêt immédiat. Anticoagulant non-héparinique (argatroban, danaparoïde)'),
('énoxaparine','pathologie','Insuffisance rénale sévère (DFG < 30 mL/min)','relative','Énoxaparine accumulé en insuffisance rénale sévère avec risque hémorragique majeur','Accumulation de énoxaparine en cas d''insuffisance rénale','CI absolue pour AODs (DFG < 30). Préférer HNF si anticoagulation requise'),
('énoxaparine','pathologie','Grossesse','relative','Énoxaparine (HBPM) déconseillé — données insuffisantes','Passage placentaire de énoxaparine insuffisamment étudié','HBPM recommandée pendant toute la grossesse comme alternative anticoagulante de référence'),
('énoxaparine','pathologie','Chirurgie récente à haut risque hémorragique','absolue','Énoxaparine contre-indiqué dans les suites immédiates d''une chirurgie à risque hémorragique élevé','Inhibition de la coagulation par énoxaparine compromet l''hémostase chirurgicale','Respecter les délais post-opératoires selon le type de chirurgie et HBPM'),
('énoxaparine','pathologie','HTA sévère non contrôlée (PA > 180/110 mmHg)','relative','Énoxaparine déconseillé en HTA sévère non contrôlée par risque d''AVC hémorragique','HTA sévère fragilise les vaisseaux. Anticoagulation par énoxaparine augmente le risque cérébral','Contrôler la PA avant anticoagulation. Évaluation neurologique si nécessaire'),
